     1→"use client";
     2→
     3→import Link from "next/link";
     4→import { usePathname } from "next/navigation";
     5→import {
     6→  LayoutDashboard,
     7→  FolderKanban,
     8→  Package,
     9→  Bell,
    10→  Megaphone,
    11→} from "lucide-react";
    12→import { cn } from "@/lib/utils";
    13→
    14→const navItems = [
    15→  { href: "/", label: "Dashboard", icon: LayoutDashboard },
    16→  { href: "/projects", label: "Projects", icon: FolderKanban },
    17→  { href: "/releases", label: "Releases", icon: Package },
    18→  { href: "/channels", label: "Channels", icon: Megaphone },
    19→  { href: "/subscriptions", label: "Subscriptions", icon: Bell },
