    22→export function Sidebar() {
    23→  const pathname = usePathname();
    24→
    25→  return (
    26→    <aside
    27→      className="flex w-[200px] shrink-0 flex-col"
    28→      style={{ backgroundColor: "#16181c" }}
    29→    >
    30→      {/* Logo */}
    31→      <div className="flex h-12 items-center gap-2 px-4">
    32→        <span
    33→          className="h-2.5 w-2.5 rounded-full shrink-0"
    34→          style={{ backgroundColor: "#e8601a" }}
    35→        />
    36→        <Link
    37→          href="/"
    38→          className="text-[16px] italic text-white"
    39→          style={{ fontFamily: "var(--font-fraunces)" }}
    40→        >
    41→          Changelogue
    42→        </Link>
    43→      </div>
    44→
    45→      {/* Nav */}
    46→      <nav className="flex-1 px-0 pt-2">
    47→        {navItems.map((item) => {
    48→          const isActive =
    49→            item.href === "/"
