     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import {
     7→  projects as projectsApi,
     8→  releases as releasesApi,
     9→  semanticReleases as srApi,
    10→  sources as sourcesApi,
    11→} from "@/lib/api/client";
    12→import { getProviderIcon } from "@/components/ui/provider-badge";
    13→import { timeAgo } from "@/lib/format";
    14→import { Plus } from "lucide-react";
    15→import type { Project } from "@/lib/api/types";
    16→
    17→const CHUNK_SIZE = 3;
    18→
    19→function ReleaseChips({ projectId }: { projectId: string }) {
    20→  const [limit, setLimit] = useState(CHUNK_SIZE);
    21→  const { data } = useSWR(
    22→    `projects/${projectId}/releases?limit=${limit + 1}`,
    23→    () => releasesApi.listByProject(projectId, 1, limit + 1)
    24→  );
    25→  const { data: sourcesData } = useSWR(
    26→    `projects/${projectId}/sources`,
    27→    () => sourcesApi.listByProject(projectId)
    28→  );
    29→  const items = data?.data ?? [];
    30→  const hasMore = items.length > limit;
    31→  const shown = items.slice(0, limit);
    32→
    33→  const providerMap = new Map<string, string>();
    34→  for (const s of sourcesData?.data ?? []) {
    35→    providerMap.set(s.id, s.provider);
    36→  }
    37→
    38→  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loading…</span>;
    39→  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">—</span>;
    40→
    41→  return (
    42→    <div className="flex flex-wrap items-center gap-1">
    43→      {shown.map((r) => {
    44→        const provider = providerMap.get(r.source_id);
    45→        const Icon = provider ? getProviderIcon(provider) : undefined;
    46→        return (
    47→          <Link
    48→            key={r.id}
    49→            href={`/releases/${r.id}`}
    50→            className="inline-flex items-center gap-1 rounded px-1.5 py-0.5 text-[12px] leading-none text-[#374151] transition-colors hover:bg-[#e8e8e5]"
    51→            style={{ backgroundColor: "#f3f3f1", fontFamily: "'JetBrains Mono', monospace" }}
    52→          >
    53→            {Icon && <Icon size={11} className="shrink-0 text-[#6b7280]" />}
    54→            {r.version}
    55→          </Link>
    56→        );
    57→      })}
    58→      {hasMore && (
    59→        <button
    60→          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    61→          className="text-[11px] text-[#e8601a] hover:underline"
    62→          style={{ fontFamily: "var(--font-dm-sans)" }}
    63→        >
    64→          more…
    65→        </button>
    66→      )}
    67→    </div>
    68→  );
    69→}
    70→
    71→function SemanticReleaseChips({ projectId }: { projectId: string }) {
    72→  const [limit, setLimit] = useState(CHUNK_SIZE);
    73→  const { data } = useSWR(
    74→    `projects/${projectId}/sr?limit=${limit + 1}`,
    75→    () => srApi.list(projectId, 1, limit + 1)
    76→  );
    77→  const items = data?.data ?? [];
    78→  const hasMore = items.length > limit;
    79→  const shown = items.slice(0, limit);
    80→
    81→  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loading…</span>;
    82→  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">—</span>;
    83→
    84→  return (
    85→    <div className="flex flex-wrap items-center gap-1">
    86→      {shown.map((sr) => (
    87→        <Link
    88→          key={sr.id}
    89→          href={`/projects/${projectId}/semantic-releases/${sr.id}`}
    90→          className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none text-[#1d4ed8] transition-colors hover:bg-[#dbeafe]"
    91→          style={{ backgroundColor: "#eff6ff", fontFamily: "'JetBrains Mono', monospace" }}
    92→        >
    93→          {sr.version}
    94→        </Link>
    95→      ))}
    96→      {hasMore && (
    97→        <button
    98→          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    99→          className="text-[11px] text-[#e8601a] hover:underline"
   100→          style={{ fontFamily: "var(--font-dm-sans)" }}
   101→        >
   102→          more…
   103→        </button>
   104→      )}
   105→    </div>
   106→  );
   107→}
   108→
   109→function ProjectRow({ project, index }: { project: Project; index: number }) {
   110→  return (
   111→    <tr
   112→      className="transition-colors duration-100 hover:bg-[#fafaf9]"
   113→      style={index > 0 ? { borderTop: "1px solid #e8e8e5" } : undefined}
   114→    >
   115→      <td className="px-4 py-2.5">
   116→        <Link
   117→          href={`/projects/${project.id}`}
   118→          className="font-medium text-[#e8601a] hover:underline"
   119→        >
   120→          {project.name}
   121→        </Link>
   122→      </td>
   123→      <td className="max-w-[220px] truncate px-4 py-2.5 text-[#6b7280]">
   124→        {project.description || "—"}
   125→      </td>
   126→      <td className="px-4 py-2.5">
   127→        <ReleaseChips projectId={project.id} />
   128→      </td>
   129→      <td className="px-4 py-2.5">
   130→        <SemanticReleaseChips projectId={project.id} />
   131→      </td>
   132→      <td className="px-4 py-2.5 text-[12px] text-[#9ca3af]">
   133→        {timeAgo(project.created_at)}
   134→      </td>
   135→    </tr>
   136→  );
   137→}
   138→
   139→export default function ProjectsPage() {
   140→  const { data, isLoading } = useSWR("projects", () => projectsApi.list());
   141→  const items = data?.data ?? [];
   142→
   143→  return (
   144→    <div className="flex flex-col gap-4 fade-in">
   145→      <div className="flex items-center justify-between">
   146→        <div>
   147→          <h1
   148→            className="text-[24px] font-semibold text-[#111113]"
   149→            style={{ fontFamily: "var(--font-fraunces)" }}
   150→          >
   151→            Projects
   152→          </h1>
   153→          <p
   154→            className="mt-1 text-[13px] text-[#6b7280]"
   155→            style={{ fontFamily: "var(--font-dm-sans)" }}
   156→          >
   157→            Tracked software projects and their recent releases.
   158→          </p>
   159→        </div>
   160→        <Link
   161→          href="/projects/new"
   162→          className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   163→          style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   164→        >
   165→          <Plus className="h-3.5 w-3.5" />
   166→          New Project
   167→        </Link>
   168→      </div>
   169→
   170→      <div
   171→        className="overflow-hidden rounded-md"
   172→        style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   173→      >
   174→        {isLoading ? (
   175→          <p
   176→            className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   177→            style={{ fontFamily: "var(--font-fraunces)" }}
   178→          >
   179→            Loading…
   180→          </p>
   181→        ) : items.length === 0 ? (
   182→          <p
   183→            className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   184→            style={{ fontFamily: "var(--font-fraunces)" }}
   185→          >
   186→            No projects yet — create one to start tracking releases
   187→          </p>
   188→        ) : (
   189→          <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
   190→            <thead>
   191→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   192→                {["Name", "Description", "Recent Releases", "Semantic Releases", "Created"].map(
   193→                  (h) => (
   194→                    <th
   195→                      key={h}
   196→                      className="px-4 py-2.5 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   197→                    >
   198→                      {h}
   199→                    </th>
   200→                  )
   201→                )}
   202→              </tr>
   203→            </thead>
   204→            <tbody>
   205→              {items.map((project, i) => (
   206→                <ProjectRow key={project.id} project={project} index={i} />
   207→              ))}
   208→            </tbody>
   209→          </table>
   210→        )}
   211→      </div>
   212→    </div>
   213→  );
   214→}
