    14→
    15→export default function SourcesPage() {
    16→  const { data: projectsData } = useSWR("projects-for-sources", () => projectsApi.list());
    17→
    18→  const { data: allSources, isLoading } = useSWR(
    19→    projectsData ? "all-sources" : null,
    20→    async () => {
    21→      if (!projectsData?.data?.length) return [];
    22→      const results = await Promise.all(
    23→        projectsData.data.map(async (p) => {
    24→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
