    23→}
    24→
    25→const PER_PAGE = 15;
    26→
    27→function getProviderUrl(
    28→  provider: string,
    29→  repository: string,
    30→  version: string
    31→): string | null {
    32→  switch (provider) {
    33→    case "github":
    34→      return `https://github.com/${repository}/releases/tag/${version}`;
