    16→interface ReleaseRow extends Release {
    17→  _repository?: string;
    18→  _provider?: string;
    19→}
    20→
    21→export function RecentReleases() {
    22→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    23→    projectsApi.list()
    24→  );
    25→
    26→  const { data: allReleases, isLoading } = useSWR(
    27→    projectsData ? "recent-releases" : null,
    28→    async () => {
    29→      if (!projectsData?.data?.length) return [];
    30→
    31→      // Fetch releases and sources in parallel per project
    32→      const projectSlice = projectsData.data.slice(0, 10);
    33→      const [releaseResults, sourceResults] = await Promise.all([
    34→        Promise.all(
    35→          projectSlice.map((p) =>
    36→            releasesApi.listByProject(p.id, 1).catch(() => null)
    37→          )
    38→        ),
    39→        Promise.all(
    40→          projectSlice.map((p) =>
    41→            sourcesApi.listByProject(p.id, 1).catch(() => null)
    42→          )
    43→        ),
    44→      ]);
    45→
    46→      // Build source_id -> repository and source_id -> provider maps
    47→      const sourceMap = new Map<string, string>();
    48→      const providerMap = new Map<string, string>();
    49→      sourceResults
    50→        .filter((r): r is NonNullable<typeof r> => r !== null)
    51→        .flatMap((r) => r.data)
    52→        .forEach((s: Source) => {
    53→          sourceMap.set(s.id, s.repository);
    54→          providerMap.set(s.id, s.provider);
    55→        });
    56→
    57→      const releases: ReleaseRow[] = releaseResults
    58→        .filter((r): r is NonNullable<typeof r> => r !== null)
    59→        .flatMap((r) => r.data)
    60→        .sort(
    61→          (a, b) =>
    62→            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
    63→        )
    64→        .slice(0, 8)
    65→        .map((rel) => ({
    66→          ...rel,
    67→          _repository: sourceMap.get(rel.source_id),
    68→          _provider: providerMap.get(rel.source_id),
    69→        }));
    70→
    71→      return releases;
    72→    }
    73→  );
    74→
    75→  return (
    76→    <div
    77→      className="rounded-lg bg-white"
    78→      style={{ border: "1px solid #e8e8e5" }}
    79→    >
    80→      {/* Header */}
    81→      <div
    82→        className="flex items-center justify-between px-5 py-4"
    83→        style={{ borderBottom: "1px solid #e8e8e5" }}
    84→      >
    85→        <h3
    86→          className="font-medium"
    87→          style={{
    88→            fontFamily: "var(--font-dm-sans)",
    89→            fontSize: "13px",
    90→            color: "#111113",
    91→          }}
    92→        >
    93→          Recent Source Releases
    94→        </h3>
    95→        <Link
    96→          href="/releases"
    97→          className="text-sm hover:underline"
    98→          style={{
    99→            fontFamily: "var(--font-dm-sans)",
   100→            fontSize: "13px",
   101→            color: "#e8601a",
   102→          }}
   103→        >
   104→          View all &rarr;
   105→        </Link>
   106→      </div>
   107→
   108→      {/* Body */}
   109→      <div>
   110→        {isLoading ? (
   111→          <div
   112→            className="py-12 text-center"
   113→            style={{
   114→              fontFamily: "var(--font-dm-sans)",
   115→              fontSize: "13px",
   116→              color: "#6b7280",
   117→            }}
   118→          >
   119→            Loading...
   120→          </div>
   121→        ) : allReleases && allReleases.length > 0 ? (
   122→          allReleases.map((release: ReleaseRow, idx: number) => {
   123→            const Icon = release._provider ? getProviderIcon(release._provider) : undefined;
   124→            return (
   125→            <Link
   126→              key={release.id}
   127→              href={`/releases/${release.id}`}
   128→              className="flex items-center justify-between px-5 py-3 transition-colors hover:bg-[#fafaf9]"
   129→              style={
   130→                idx < allReleases.length - 1
   131→                  ? { borderBottom: "1px solid #e8e8e5" }
   132→                  : undefined
   133→              }
   134→            >
   135→              <span
   136→                className="flex min-w-0 flex-1 items-center gap-1.5 truncate"
   137→                style={{
   138→                  fontFamily: "'JetBrains Mono', monospace",
   139→                  fontSize: "13px",
   140→                  color: "#6b7280",
   141→                }}
   142→              >
   143→                {Icon && <Icon size={13} className="shrink-0 text-[#9ca3af]" />}
   144→                {release._repository ?? release.source_id.slice(0, 12)}
   145→              </span>
   146→              <div className="ml-3 flex items-center gap-3">
   147→                <VersionChip version={release.version} />
   148→                <span
   149→                  className="whitespace-nowrap"
   150→                  style={{
   151→                    fontFamily: "var(--font-dm-sans)",
   152→                    fontSize: "12px",
   153→                    color: "#9ca3af",
   154→                  }}
   155→                >
   156→                  {timeAgo(release.released_at ?? release.created_at)}
   157→                </span>
   158→              </div>
   159→            </Link>
   160→          );})
   161→        ) : (
   162→          <div className="py-12 text-center">
   163→            <p
   164→              style={{
   165→                fontFamily: "var(--font-fraunces)",
   166→                fontStyle: "italic",
   167→                fontSize: "14px",
   168→                color: "#9ca3af",
   169→              }}
   170→            >
   171→              No releases yet
   172→            </p>
   173→          </div>
   174→        )}
   175→      </div>
   176→    </div>
   177→  );
   178→}
