   189→// --- ReleasesStore ---
   190→
   191→func (s *PgStore) ListReleasesBySource(ctx context.Context, sourceID string, page, perPage int) ([]models.Release, int, error) {
   192→	var total int
   193→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases WHERE source_id = $1`, sourceID).Scan(&total)
   194→	if err != nil {
   195→		return nil, 0, fmt.Errorf("count releases: %w", err)
   196→	}
   197→	offset := (page - 1) * perPage
