   638→
   639→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   640→// This follows the transactional outbox pattern for zero-loss guarantee.
   641→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger string) error {
   642→	tx, err := s.pool.Begin(ctx)
   643→	if err != nil {
   644→		return fmt.Errorf("begin tx: %w", err)
   645→	}
   646→	defer tx.Rollback(ctx)
   647→
   648→	var runID string
   649→	err = tx.QueryRow(ctx,
   650→		`INSERT INTO agent_runs (project_id, trigger, status)
   651→		 VALUES ($1, $2, 'pending')
   652→		 RETURNING id`, projectID, trigger,
   653→	).Scan(&runID)
   654→	if err != nil {
   655→		return fmt.Errorf("insert agent run: %w", err)
   656→	}
   657→
   658→	if s.river != nil {
   659→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   660→			AgentRunID: runID,
   661→			ProjectID:  projectID,
   662→		}, nil)
   663→		if err != nil {
   664→			return fmt.Errorf("enqueue agent job: %w", err)
   665→		}
   666→	}
   667→
   668→	return tx.Commit(ctx)
   669→}
