   671→// --- OrchestratorStore (agent layer) ---
   672→
   673→// UpdateAgentRunStatus sets the status of an agent run and updates the
   674→// started_at timestamp when transitioning to "running".
   675→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   676→	var query string
   677→	switch status {
   678→	case "running":
   679→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   680→	case "completed":
   681→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   682→	default:
   683→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   684→	}
   685→	tag, err := s.pool.Exec(ctx, query, status, id)
   686→	if err != nil {
   687→		return fmt.Errorf("update agent run status: %w", err)
   688→	}
   689→	if tag.RowsAffected() == 0 {
   690→		return fmt.Errorf("agent run not found: %s", id)
   691→	}
   692→	return nil
   693→}
   694→
   695→// CreateSemanticRelease inserts a semantic release and its source release links
   696→// in a single transaction. The sr.ID field is populated on success.
   697→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   698→	tx, err := s.pool.Begin(ctx)
   699→	if err != nil {
   700→		return fmt.Errorf("begin tx: %w", err)
   701→	}
   702→	defer tx.Rollback(ctx)
   703→
   704→	err = tx.QueryRow(ctx,
   705→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   706→		 VALUES ($1, $2, $3, $4, $5)
   707→		 RETURNING id, created_at`,
   708→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   709→	).Scan(&sr.ID, &sr.CreatedAt)
   710→	if err != nil {
   711→		return fmt.Errorf("insert semantic release: %w", err)
   712→	}
   713→
   714→	for _, relID := range releaseIDs {
   715→		_, err = tx.Exec(ctx,
   716→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   717→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   718→			sr.ID, relID,
   719→		)
   720→		if err != nil {
   721→			return fmt.Errorf("insert semantic release source: %w", err)
   722→		}
   723→	}
   724→
   725→	return tx.Commit(ctx)
   726→}
   727→
   728→// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
   729→func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
   730→	tag, err := s.pool.Exec(ctx,
   731→		`UPDATE agent_runs SET semantic_release_id = $1 WHERE id = $2`,
   732→		semanticReleaseID, id,
   733→	)
   734→	if err != nil {
   735→		return fmt.Errorf("update agent run result: %w", err)
   736→	}
   737→	if tag.RowsAffected() == 0 {
   738→		return fmt.Errorf("agent run not found: %s", id)
   739→	}
   740→	return nil
   741→}
   742→
   743→// ListProjectSubscriptions returns all project-level subscriptions for a given project.
   744→func (s *PgStore) ListProjectSubscriptions(ctx context.Context, projectID string) ([]models.Subscription, error) {
   745→	rows, err := s.pool.Query(ctx,
   746→		`SELECT id, channel_id, type, source_id, project_id, COALESCE(version_filter,''), created_at
   747→		 FROM subscriptions
   748→		 WHERE type = 'project' AND project_id = $1`, projectID)
   749→	if err != nil {
   750→		return nil, fmt.Errorf("list project subscriptions: %w", err)
   751→	}
   752→	defer rows.Close()
   753→	var subs []models.Subscription
   754→	for rows.Next() {
   755→		var sub models.Subscription
   756→		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
   757→			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
   758→			return nil, fmt.Errorf("scan subscription: %w", err)
   759→		}
   760→		subs = append(subs, sub)
   761→	}
   762→	return subs, nil
   763→}
