   775→func (s *PgStore) GetStats(ctx context.Context) (*DashboardStats, error) {
   776→	var stats DashboardStats
   777→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases`).Scan(&stats.TotalReleases); err != nil {
   778→		return nil, fmt.Errorf("count releases: %w", err)
   779→	}
   780→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources WHERE enabled = true`).Scan(&stats.ActiveSources); err != nil {
   781→		return nil, fmt.Errorf("count active sources: %w", err)
   782→	}
   783→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&stats.TotalProjects); err != nil {
   784→		return nil, fmt.Errorf("count projects: %w", err)
   785→	}
   786→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM agent_runs WHERE status = 'pending'`).Scan(&stats.PendingAgentRuns); err != nil {
   787→		return nil, fmt.Errorf("count pending agent runs: %w", err)
   788→	}
   789→	return &stats, nil
   790→}
